mapper.select:
SELECT * FROM ( SELECT P.post_seq, P.board_id, P.post_title, P.reg_id, P.reg_nm, P.reg_dt, P.read_cnt, P.post_status, P.post_use_yn, P.secret_yn, P.notice_yn, P.notice_begin_dt, P.notice_end_dt, P.extra_col1, P.extra_col2, P.extra_col3, P.extra_col4, P.extra_col5, (SELECT COUNT(*) FROM TB_POST_FILE_INFO F WHERE F.post_seq = P.post_seq AND F.board_id = P.board_id) AS file_cnt, (SELECT COUNT(*) FROM TB_POST_REPLY_INFO R WHERE R.post_seq = P.post_seq AND R.board_id = P.board_id AND R.reply_use_yn = 'Y') AS reply_cnt, ROW_NUMBER() OVER(ORDER BY CASE WHEN P.notice_yn = 'Y' AND GETDATE() BETWEEN P.notice_begin_dt AND DATEADD(DAY,1,P.notice_end_dt) THEN 0 ELSE 1 END, P.post_seq DESC ) AS rn FROM TB_POST_INFO P WHERE P.board_id = #{boardId} AND P.post_use_yn = 'Y'
AND P.post_status = #{postStatus}
AND P.post_title LIKE '%' + #{keyword} + '%'
AND P.post_content LIKE '%' + #{keyword} + '%'
AND P.reg_nm LIKE '%' + #{keyword} + '%'
AND (P.post_title LIKE '%' + #{keyword} + '%' OR P.post_content LIKE '%' + #{keyword} + '%' OR P.reg_nm LIKE '%' + #{keyword} + '%')
AND P.extra_col1 LIKE '%' + #{keyword} + '%'
AND P.extra_col2 LIKE '%' + #{keyword} + '%'
AND P.reg_id = #{userId}
) AS numbered WHERE rn > #{minSn} AND rn <= #{maxSn}

mapper.update:
UPDATE TB_POST_INFO SET
    post_status = #{postStatus},
    status_dt   = GETDATE()
WHERE post_seq = #{postSeq}
  AND board_id = #{boardId}

